import React, { useCallback, useEffect, useState } from 'react';
import { Loader, Plus, Save, Search, Trash2, UserCheck, X } from 'lucide-react';
import api from '../../services/api';

const ALL_PAGES = ['Pos', 'Orders', 'Products', 'Customers', 'Reports', 'Profile', 'ChangePassword', 'Overview'];

const Toggle = ({ enabled, onChange, saving }) => (
  <button
    type="button"
    onClick={onChange}
    disabled={saving}
    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${
      enabled ? 'bg-blue-600' : 'bg-gray-300'
    } ${saving ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
  >
    <span
      className={`inline-block h-4 w-4 transform rounded-full bg-white shadow transition-transform ${
        enabled ? 'translate-x-6' : 'translate-x-1'
      }`}
    />
  </button>
);

const StaffPermissions = () => {
  const [rows, setRows] = useState([]);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [savingId, setSavingId] = useState(null);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');

  // Add new user form
  const [showAdd, setShowAdd] = useState(false);
  const [addUserId, setAddUserId] = useState('');
  const [addSaving, setAddSaving] = useState(false);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const [permRes, userRes] = await Promise.all([
        api.get('/staffpermissions'),
        api.get('/users?page=1&pageSize=500'),
      ]);
      setRows(permRes.data || []);
      setUsers(userRes.data?.items || []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load staff permissions.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const getPages = (allowedPages) =>
    (allowedPages || '').split(',').map((p) => p.trim()).filter(Boolean);

  const togglePage = async (row, page) => {
    const current = getPages(row.allowedPages);
    const updated = current.includes(page)
      ? current.filter((p) => p !== page)
      : [...current, page];
    const newAllowedPages = updated.join(',');

    setSavingId(`${row.id}-${page}`);
    try {
      await api.put(`/staffpermissions/${row.id}`, {
        userId: row.userId,
        allowedPages: newAllowedPages,
      });
      setRows((prev) =>
        prev.map((r) => r.id === row.id ? { ...r, allowedPages: newAllowedPages } : r)
      );
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to update permission.');
    } finally {
      setSavingId(null);
    }
  };

  const onDelete = async (id) => {
    if (!window.confirm('Delete this permission record?')) return;
    try {
      await api.delete(`/staffpermissions/${id}`);
      setRows((prev) => prev.filter((r) => r.id !== id));
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to delete permission.');
    }
  };

  const onAddUser = async () => {
    if (!addUserId) return;
    setAddSaving(true);
    setError('');
    try {
      await api.post('/staffpermissions', {
        userId: Number(addUserId),
        allowedPages: '',
      });
      setShowAdd(false);
      setAddUserId('');
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to add permission.');
    } finally {
      setAddSaving(false);
    }
  };

  const assignedUserIds = new Set(rows.map((r) => r.userId));
  const availableUsers = users.filter((u) => !assignedUserIds.has(u.userId));

  const filteredRows = rows.filter((r) => {
    const name = (r.user?.fullName || r.user?.username || '').toLowerCase();
    return name.includes(search.toLowerCase());
  });

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-900">Staff Permissions</h2>
        <button
          onClick={() => setShowAdd(true)}
          className="inline-flex items-center gap-2 px-4 py-2 rounded-lg bg-blue-600 text-white text-sm font-medium hover:bg-blue-700"
        >
          <Plus className="w-4 h-4" /> Add Staff
        </button>
      </div>

      {error && (
        <div className="p-3 text-sm border border-red-200 bg-red-50 text-red-700 rounded-lg">
          {error}
        </div>
      )}

      {/* Add Staff Modal */}
      {showAdd && (
        <div className="bg-white border border-gray-200 rounded-xl p-4 flex items-center gap-3">
          <select
            value={addUserId}
            onChange={(e) => setAddUserId(e.target.value)}
            className="flex-1 px-3 py-2 border border-gray-300 rounded-lg text-sm"
          >
            <option value="">Select a user to add...</option>
            {availableUsers.map((u) => (
              <option key={u.userId} value={u.userId}>
                {u.fullName || u.username} ({u.username})
              </option>
            ))}
          </select>
          <button
            onClick={onAddUser}
            disabled={!addUserId || addSaving}
            className="inline-flex items-center gap-2 px-4 py-2 rounded-lg bg-blue-600 text-white text-sm disabled:opacity-50"
          >
            <Save className="w-4 h-4" /> {addSaving ? 'Saving...' : 'Save'}
          </button>
          <button
            onClick={() => { setShowAdd(false); setAddUserId(''); }}
            className="p-2 rounded-lg hover:bg-gray-100 text-gray-500"
          >
            <X className="w-4 h-4" />
          </button>
        </div>
      )}

      {/* Search */}
      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
        <input
          type="text"
          placeholder="Search staff by name..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      {/* Table */}
      <div className="bg-white border border-gray-200 rounded-xl overflow-x-auto">
        {loading ? (
          <div className="py-10 flex justify-center">
            <Loader className="w-6 h-6 animate-spin text-blue-600" />
          </div>
        ) : filteredRows.length === 0 ? (
          <div className="py-10 text-center text-gray-400 text-sm">No staff permissions found.</div>
        ) : (
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase whitespace-nowrap">Staff</th>
                {ALL_PAGES.map((page) => (
                  <th key={page} className="px-3 py-3 text-center text-xs font-semibold text-gray-700 uppercase whitespace-nowrap">
                    {page}
                  </th>
                ))}
                <th className="px-4 py-3 text-center text-xs font-semibold text-gray-700 uppercase">Delete</th>
              </tr>
            </thead>
            <tbody>
              {filteredRows.map((r) => {
                const pages = getPages(r.allowedPages);
                return (
                  <tr key={r.id} className="border-t border-gray-100 hover:bg-gray-50">
                    <td className="px-4 py-3 font-medium text-gray-900 whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        <UserCheck className="w-4 h-4 text-blue-500 flex-shrink-0" />
                        {r.user?.fullName || r.user?.username || `User #${r.userId}`}
                      </div>
                    </td>
                    {ALL_PAGES.map((page) => (
                      <td key={page} className="px-3 py-3 text-center">
                        <div className="flex justify-center">
                          <Toggle
                            enabled={pages.includes(page)}
                            onChange={() => togglePage(r, page)}
                            saving={savingId === `${r.id}-${page}`}
                          />
                        </div>
                      </td>
                    ))}
                    <td className="px-4 py-3 text-center">
                      <button
                        onClick={() => onDelete(r.id)}
                        className="p-2 rounded-lg hover:bg-red-50 text-red-500"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default StaffPermissions;
